import { setup, assign } from 'xstate';

type CheckoutContext = {
  address: string;
  city: string;
  card: string;
  confirmed: boolean;
};

type CheckoutEvent =
  | { type: 'ADDRESS.UPDATE'; value: string }
  | { type: 'CITY.UPDATE'; value: string }
  | { type: 'SHIPPING.SUBMIT' }
  | { type: 'CARD.UPDATE'; value: string }
  | { type: 'PAYMENT.SUBMIT' }
  | { type: 'REVIEW.CONFIRM' }
  | { type: 'BACK' };

export const checkoutMachine = setup({
  types: {
    context: {} as CheckoutContext,
    events: {} as CheckoutEvent,
  },
  guards: {
    shippingValid: ({ context }) =>
      context.address.trim().length > 0 && context.city.trim().length > 0,
    paymentValid: ({ context }) => /^\d{16}$/.test(context.card),
  },
}).createMachine({
  id: 'checkout',
  initial: 'shipping',
  context: { address: '', city: '', card: '', confirmed: false },
  states: {
    shipping: {
      on: {
        'ADDRESS.UPDATE': {
          actions: assign({ address: ({ event }) => event.value }),
        },
        'CITY.UPDATE': {
          actions: assign({ city: ({ event }) => event.value }),
        },
        'SHIPPING.SUBMIT': { guard: 'shippingValid', target: 'payment' },
      },
    },
    payment: {
      on: {
        'CARD.UPDATE': {
          actions: assign({ card: ({ event }) => event.value }),
        },
        'PAYMENT.SUBMIT': { guard: 'paymentValid', target: 'review' },
        BACK: 'shipping',
      },
    },
    review: {
      on: {
        'REVIEW.CONFIRM': {
          target: 'done',
          actions: assign({ confirmed: true }),
        },
        BACK: 'payment',
      },
    },
    done: { type: 'final' },
  },
});
