A multi-step form in XState v5 models each step as a compound or sibling state. Each step handles its own field-update events and exposes a NEXT transition guarded by the step's validation rule. Navigating backward is just an extra event (BACK) on each non-initial step. The flow terminates in a `type: 'final'` state so subscribers can detect completion from the snapshot's status.

```ts
import { setup, assign } from 'xstate';

type LoginContext = { email: string; password: string };

type LoginEvent =
  | { type: 'EMAIL.SET'; value: string }
  | { type: 'EMAIL.NEXT' }
  | { type: 'PASSWORD.SET'; value: string }
  | { type: 'PASSWORD.SUBMIT' }
  | { type: 'BACK' };

export const loginMachine = setup({
  types: {
    context: {} as LoginContext,
    events: {} as LoginEvent,
  },
  guards: {
    emailOk: ({ context }) => /.+@.+\..+/.test(context.email),
    passwordOk: ({ context }) => context.password.length >= 8,
  },
}).createMachine({
  id: 'login',
  initial: 'email',
  context: { email: '', password: '' },
  states: {
    email: {
      on: {
        'EMAIL.SET': {
          actions: assign({ email: ({ event }) => event.value }),
        },
        'EMAIL.NEXT': { guard: 'emailOk', target: 'password' },
      },
    },
    password: {
      on: {
        'PASSWORD.SET': {
          actions: assign({ password: ({ event }) => event.value }),
        },
        'PASSWORD.SUBMIT': { guard: 'passwordOk', target: 'authenticated' },
        BACK: 'email',
      },
    },
    authenticated: { type: 'final' },
  },
});
