type ApplicationContext = {
  resume: string;
  coverLetter: string;
  references: string[];
};

type ApplicationEvent =
  | { type: 'RESUME.SET'; value: string }
  | { type: 'RESUME.NEXT' }
  | { type: 'COVER.SET'; value: string }
  | { type: 'COVER.NEXT' }
  | { type: 'REF.ADD'; value: string }
  | { type: 'REF.REMOVE'; index: number }
  | { type: 'SUBMIT' }
  | { type: 'BACK' };

export const applicationMachine = setup({
  types: {
    context: {} as ApplicationContext,
    events: {} as ApplicationEvent,
  },
  guards: {
    hasResume: ({ context }) => context.resume.trim().length > 0,
    coverLongEnough: ({ context }) => context.coverLetter.trim().length >= 20,
    hasReferences: ({ context }) => context.references.length >= 1,
  },
}).createMachine({
  id: 'application',
  initial: 'resume',
  context: { resume: '', coverLetter: '', references: [] },
  states: {
    resume: {
      on: {
        'RESUME.SET': {
          actions: assign({ resume: ({ event }) => event.value }),
        },
        'RESUME.NEXT': { guard: 'hasResume', target: 'cover' },
      },
    },
    cover: {
      on: {
        'COVER.SET': {
          actions: assign({ coverLetter: ({ event }) => event.value }),
        },
        'COVER.NEXT': { guard: 'coverLongEnough', target: 'references' },
        BACK: 'resume',
      },
    },
    references: {
      on: {
        'REF.ADD': {
          actions: assign({
            references: ({ context, event }) => [
              ...context.references,
              event.value,
            ],
          }),
        },
        'REF.REMOVE': {
          actions: assign({
            references: ({ context, event }) =>
              context.references.filter((_, i) => i !== event.index),
          }),
        },
        SUBMIT: { guard: 'hasReferences', target: 'submitted' },
        BACK: 'cover',
      },
    },
    submitted: { type: 'final' },
  },
});
